class Solution:
    def smallestEvenMultiple(self, n):
        m = 2
        while True:
            if m % 2 == 0 and m % n == 0:
                return m
            m += 1

solutions.python:
class Solution:
    def smallestEvenMultiple(self, n):
        return n if n % 2 == 0 else n * 2

